class Solution:
    def minimumOperations(self, root):
        from collections import deque
        total = 0
        q = deque([root]) if root else deque()
        while q:
            level = []
            for _ in range(len(q)):
                node = q.popleft()
                level.append(node.val)
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            # naive selection-sort swap count
            arr = level[:]
            ops = 0
            for i in range(len(arr)):
                mi = i
                for j in range(i + 1, len(arr)):
                    if arr[j] < arr[mi]:
                        mi = j
                if mi != i:
                    arr[i], arr[mi] = arr[mi], arr[i]
                    ops += 1
            total += ops
        return total

