from collections import deque
class Solution:
    def minimumOperations(self, root):
        total = 0
        q = deque([root]) if root else deque()
        while q:
            level = []
            for _ in range(len(q)):
                node = q.popleft()
                level.append(node.val)
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            order = sorted(range(len(level)), key=lambda i: level[i])
            target = [0] * len(level)
            for sorted_pos, orig_idx in enumerate(order):
                target[orig_idx] = sorted_pos
            visited = [False] * len(level)
            for i in range(len(level)):
                if visited[i] or target[i] == i:
                    visited[i] = True
                    continue
                cyc = 0
                j = i
                while not visited[j]:
                    visited[j] = True
                    j = target[j]
                    cyc += 1
                total += cyc - 1
        return total

