var minimumOperations = function(root) {
    let total = 0;
    let q = root ? [root] : [];
    while (q.length) {
        const level = [];
        const next = [];
        for (const node of q) {
            level.push(node.val);
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        const order = level.map((_, i) => i).sort((a, b) => level[a] - level[b]);
        const target = new Array(level.length);
        for (let sp = 0; sp < order.length; sp++) target[order[sp]] = sp;
        const visited = new Array(level.length).fill(false);
        for (let i = 0; i < level.length; i++) {
            if (visited[i] || target[i] === i) { visited[i] = true; continue; }
            let cyc = 0, j = i;
            while (!visited[j]) { visited[j] = true; j = target[j]; cyc++; }
            total += cyc - 1;
        }
        q = next;
    }
    return total;
};
